48	const (
49		// MaxDisruptedPodSize is the max size of PodDisruptionBudgetStatus.DisruptedPods. API server eviction
50		// subresource handler will refuse to evict pods covered by the corresponding PDB
51		// if the size of the map exceeds this value. It means a large number of
52		// evictions have been approved by the API server but not noticed by the PDB controller yet.
53		// This situation should self-correct because the PDB controller removes
54		// entries from the map automatically after the PDB DeletionTimeout regardless.
55		MaxDisruptedPodSize = 2000
56	)
