58	// EvictionsRetry is the retry for a conflict where multiple clients
59	// are making changes to the same resource.
60	var EvictionsRetry = wait.Backoff{
61		Steps:    20,
62		Duration: 500 * time.Millisecond,
63		Factor:   1.0,
64		Jitter:   0.1,
65	}
