109	// Propagate dry-run takes the dry-run option from the request and pushes it into the eviction object.
110	// It returns an error if they have non-matching dry-run options.
111	func propagateDryRun(eviction *policy.Eviction, options *metav1.CreateOptions) (*metav1.DeleteOptions, error) {
112		if eviction.DeleteOptions == nil {
113			return &metav1.DeleteOptions{DryRun: options.DryRun}, nil
114		}
115		if len(eviction.DeleteOptions.DryRun) == 0 {
116			eviction.DeleteOptions.DryRun = options.DryRun
117			return eviction.DeleteOptions, nil
118		}
119		if len(options.DryRun) == 0 {
120			return eviction.DeleteOptions, nil
121		}
122	
123		if !reflect.DeepEqual(options.DryRun, eviction.DeleteOptions.DryRun) {
124			return nil, fmt.Errorf("Non-matching dry-run options in request and content: %v and %v", options.DryRun, eviction.DeleteOptions.DryRun)
125		}
126		return eviction.DeleteOptions, nil
127	}
