129	// Create attempts to create a new eviction.  That is, it tries to evict a pod.
130	func (r *EvictionREST) Create(ctx context.Context, name string, obj runtime.Object, createValidation rest.ValidateObjectFunc, options *metav1.CreateOptions) (runtime.Object, error) {
131		eviction, ok := obj.(*policy.Eviction)
132		if !ok {
133			return nil, errors.NewBadRequest(fmt.Sprintf("not a Eviction object: %T", obj))
134		}
135	
136		if name != eviction.Name {
137			return nil, errors.NewBadRequest("name in URL does not match name in Eviction object")
138		}
139	
140		if eviction.DeleteOptions != nil && ptr.Deref(eviction.DeleteOptions.IgnoreStoreReadErrorWithClusterBreakingPotential, false) {
141			errs := field.ErrorList{
142				field.Invalid(field.NewPath("deleteOptions").Child("ignoreStoreReadErrorWithClusterBreakingPotential"), true, "can not be set for pod eviction, try after removing the option"),
143			}
144			return nil, errors.NewInvalid(v1Eviction.GroupKind(), name, errs)
145		}
146	
147		originalDeleteOptions, err := propagateDryRun(eviction, options)
148		if err != nil {
149			return nil, err
150		}
151	
152		if createValidation != nil {
153			if err := createValidation(ctx, eviction.DeepCopyObject()); err != nil {
154				return nil, err
155			}
156		}
157	
158		var pod *api.Pod
159		deletedPod := false
160		// by default, retry conflict errors
161		shouldRetry := errors.IsConflict
162		if !resourceVersionIsUnset(originalDeleteOptions) {
163			// if the original options included a resourceVersion precondition, don't retry
164			shouldRetry = func(err error) bool { return false }
165		}
166	
167		err = retry.OnError(EvictionsRetry, shouldRetry, func() error {
168			pod, err = getPod(r, ctx, eviction.Name)
169			if err != nil {
170				return err
171			}
172	
173			// Evicting a terminal pod should result in direct deletion of pod as it already caused disruption by the time we are evicting.
174			// There is no need to check for pdb.
175			if !canIgnorePDB(pod) {
176				// Pod is not in a state where we can skip checking PDBs, exit the loop, and continue to PDB checks.
177				return nil
178			}
179	
180			// the PDB can be ignored, so delete the pod
181			deleteOptions := originalDeleteOptions
182	
183			// We should check if resourceVersion is already set by the requestor
184			// as it might be older than the pod we just fetched and should be
185			// honored.
186			if shouldEnforceResourceVersion(pod) && resourceVersionIsUnset(originalDeleteOptions) {
187				// Set deleteOptions.Preconditions.ResourceVersion to ensure we're not
188				// racing with another PDB-impacting process elsewhere.
189				deleteOptions = deleteOptions.DeepCopy()
190				setPreconditionsResourceVersion(deleteOptions, &pod.ResourceVersion)
191			}
192			err = addConditionAndDeletePod(r, ctx, eviction.Name, rest.ValidateAllObjectFunc, deleteOptions)
193			if err != nil {
194				return err
195			}
196			deletedPod = true
197			return nil
198		})
199		switch {
200		case err != nil:
201			// this can happen in cases where the PDB can be ignored, but there was a problem issuing the pod delete:
202			// maybe we conflicted too many times or we didn't have permission or something else weird.
203			return nil, err
204	
205		case deletedPod:
206			// this happens when we successfully deleted the pod.  In this case, we're done executing because we've evicted/deleted the pod
207			return &metav1.Status{Status: metav1.StatusSuccess}, nil
208	
209		default:
210			// this happens when we didn't have an error and we didn't delete the pod. The only branch that happens on is when
211			// we cannot ignored the PDB for this pod, so this is the fall through case.
212		}
213	
214		var rtStatus *metav1.Status
215		var pdbName string
216		updateDeletionOptions := false
217	
218		err = func() error {
219			pdbs, err := r.getPodDisruptionBudgets(ctx, pod)
220			if err != nil {
221				return err
222			}
223	
224			if len(pdbs) > 1 {
225				rtStatus = &metav1.Status{
226					Status:  metav1.StatusFailure,
227					Message: "This pod has more than one PodDisruptionBudget, which the eviction subresource does not support.",
228					Code:    500,
229				}
230				return nil
231			}
232			if len(pdbs) == 0 {
233				return nil
234			}
235	
236			pdb := &pdbs[0]
237			pdbName = pdb.Name
238	
239			// IsPodReady is the current implementation of IsHealthy
240			// If the pod is healthy, it should be guarded by the PDB.
241			if !podutil.IsPodReady(pod) {
242				if pdb.Spec.UnhealthyPodEvictionPolicy != nil && *pdb.Spec.UnhealthyPodEvictionPolicy == policyv1.AlwaysAllow {
243					// Delete the unhealthy pod, it doesn't count towards currentHealthy and desiredHealthy and we should not decrement disruptionsAllowed.
244					updateDeletionOptions = true
245					return nil
246				}
247				// default nil and IfHealthyBudget policy
248				if pdb.Status.CurrentHealthy >= pdb.Status.DesiredHealthy && pdb.Status.DesiredHealthy > 0 {
249					// Delete the unhealthy pod, it doesn't count towards currentHealthy and desiredHealthy and we should not decrement disruptionsAllowed.
250					// Application guarded by the PDB is not disrupted at the moment and deleting unhealthy (unready) pod will not disrupt it.
251					updateDeletionOptions = true
252					return nil
253				}
254				// confirm no disruptions allowed in checkAndDecrement
255			}
256	
257			refresh := false
258			err = retry.RetryOnConflict(EvictionsRetry, func() error {
259				if refresh {
260					pdb, err = r.podDisruptionBudgetClient.PodDisruptionBudgets(pod.Namespace).Get(context.TODO(), pdbName, metav1.GetOptions{})
261					if err != nil {
262						return err
263					}
264				}
265				// Try to verify-and-decrement
266	
267				// If it was false already, or if it becomes false during the course of our retries,
268				// raise an error marked as a 429.
269				if err = r.checkAndDecrement(pod.Namespace, pod.Name, *pdb, dryrun.IsDryRun(originalDeleteOptions.DryRun)); err != nil {
270					refresh = true
271					return err
272				}
273				return nil
274			})
275			return err
276		}()
277		if wait.Interrupted(err) {
278			err = errors.NewTimeoutError(fmt.Sprintf("couldn't update PodDisruptionBudget %q due to conflicts", pdbName), 10)
279		}
280		if err != nil {
281			return nil, err
282		}
283	
284		if rtStatus != nil {
285			return rtStatus, nil
286		}
287	
288		// At this point there was either no PDB or we succeeded in decrementing or
289		// the pod was unhealthy (unready) and we have enough healthy replicas
290	
291		deleteOptions := originalDeleteOptions
292	
293		// Set deleteOptions.Preconditions.ResourceVersion to ensure
294		// the pod hasn't been considered healthy (ready) since we calculated
295		if updateDeletionOptions {
296			// Take a copy so we can compare to client-provied Options later.
297			deleteOptions = deleteOptions.DeepCopy()
298			setPreconditionsResourceVersion(deleteOptions, &pod.ResourceVersion)
299		}
300	
301		// Try the delete
302		err = addConditionAndDeletePod(r, ctx, eviction.Name, rest.ValidateAllObjectFunc, deleteOptions)
303		if err != nil {
304			if errors.IsConflict(err) && updateDeletionOptions &&
305				(originalDeleteOptions.Preconditions == nil || originalDeleteOptions.Preconditions.ResourceVersion == nil) {
306				// If we encounter a resource conflict error, we updated the deletion options to include them,
307				// and the original deletion options did not specify ResourceVersion, we send back
308				// TooManyRequests so clients will retry.
309				return nil, createTooManyRequestsError(pdbName)
310			}
311			return nil, err
312		}
313	
314		// Success!
315		return &metav1.Status{Status: metav1.StatusSuccess}, nil
316	}
