318	func addConditionAndDeletePod(r *EvictionREST, ctx context.Context, name string, validation rest.ValidateObjectFunc, options *metav1.DeleteOptions) error {
319		if !dryrun.IsDryRun(options.DryRun) {
320			getLatestPod := func(_ context.Context, _, oldObj runtime.Object) (runtime.Object, error) {
321				// Throwaway the newObj. We care only about the latest pod obtained from etcd (oldObj).
322				// So we can add DisruptionTarget condition in conditionAppender without conflicts.
323				latestPod := oldObj.(*api.Pod).DeepCopy()
324				if options.Preconditions != nil {
325					if uid := options.Preconditions.UID; uid != nil && len(*uid) > 0 && *uid != latestPod.UID {
326						return nil, errors.NewConflict(
327							schema.GroupResource{Group: "", Resource: "Pod"},
328							latestPod.Name,
329							fmt.Errorf("the UID in the precondition (%s) does not match the UID in record (%s). The object might have been deleted and then recreated", *uid, latestPod.UID),
330						)
331					}
332					if rv := options.Preconditions.ResourceVersion; rv != nil && len(*rv) > 0 && *rv != latestPod.ResourceVersion {
333						return nil, errors.NewConflict(
334							schema.GroupResource{Group: "", Resource: "Pod"},
335							latestPod.Name,
336							fmt.Errorf("the ResourceVersion in the precondition (%s) does not match the ResourceVersion in record (%s). The object might have been modified", *rv, latestPod.ResourceVersion),
337						)
338					}
339				}
340				return latestPod, nil
341			}
342	
343			conditionAppender := func(_ context.Context, newObj, _ runtime.Object) (runtime.Object, error) {
344				podObj := newObj.(*api.Pod)
345				podutil.UpdatePodCondition(&podObj.Status, &api.PodCondition{
346					Type:    api.DisruptionTarget,
347					Status:  api.ConditionTrue,
348					Reason:  "EvictionByEvictionAPI",
349					Message: "Eviction API: evicting",
350				})
351				return podObj, nil
352			}
353	
354			podUpdatedObjectInfo := rest.DefaultUpdatedObjectInfo(nil, getLatestPod, conditionAppender) // order important
355	
356			updatedPodObject, _, err := r.store.Update(ctx, name, podUpdatedObjectInfo, rest.ValidateAllObjectFunc, rest.ValidateAllObjectUpdateFunc, false, &metav1.UpdateOptions{})
357			if err != nil {
358				return err
359			}
360	
361			if !resourceVersionIsUnset(options) {
362				newResourceVersion, err := meta.NewAccessor().ResourceVersion(updatedPodObject)
363				if err != nil {
364					return err
365				}
366				// bump the resource version, since we are the one who modified it via the update
367				options = options.DeepCopy()
368				options.Preconditions.ResourceVersion = &newResourceVersion
369			}
370		}
371		_, _, err := r.store.Delete(ctx, name, rest.ValidateAllObjectFunc, options)
372		return err
373	}
