390	// canIgnorePDB returns true for pod conditions that allow the pod to be deleted
391	// without checking PDBs.
392	func canIgnorePDB(pod *api.Pod) bool {
393		if pod.Status.Phase == api.PodSucceeded || pod.Status.Phase == api.PodFailed ||
394			pod.Status.Phase == api.PodPending || !pod.ObjectMeta.DeletionTimestamp.IsZero() {
395			return true
396		}
397		return false
398	}
399	
400	func shouldEnforceResourceVersion(pod *api.Pod) bool {
401		// We don't need to enforce ResourceVersion for terminal pods
402		if pod.Status.Phase == api.PodSucceeded || pod.Status.Phase == api.PodFailed || !pod.ObjectMeta.DeletionTimestamp.IsZero() {
403			return false
404		}
405		// Return true for all other pods to ensure we don't race against a pod becoming
406		// healthy (ready) and violating PDBs.
407		return true
408	}
409	
410	func resourceVersionIsUnset(options *metav1.DeleteOptions) bool {
411		return options.Preconditions == nil || options.Preconditions.ResourceVersion == nil
412	}
