424	// checkAndDecrement checks if the provided PodDisruptionBudget allows any disruption.
425	func (r *EvictionREST) checkAndDecrement(namespace string, podName string, pdb policyv1.PodDisruptionBudget, dryRun bool) error {
426		if pdb.Status.ObservedGeneration < pdb.Generation {
427	
428			return createTooManyRequestsError(pdb.Name)
429		}
430		if pdb.Status.DisruptionsAllowed < 0 {
431			err := errors.NewForbidden(policy.Resource("poddisruptionbudget"), pdb.Name, goerrors.New("pdb disruptions allowed is negative"))
432			err.ErrStatus.Details.Causes = append(err.ErrStatus.Details.Causes, metav1.StatusCause{
433				Type:    policyv1.DisruptionBudgetCause,
434				Message: fmt.Sprintf("The disruption budget %s does not allow evicting pods currently: pdb disruptions allowed is negative", pdb.Name),
435			})
436			return err
437		}
438		if len(pdb.Status.DisruptedPods) > MaxDisruptedPodSize {
439			err := errors.NewForbidden(policy.Resource("poddisruptionbudget"), pdb.Name, goerrors.New("DisruptedPods map too big - too many evictions not confirmed by PDB controller"))
440			err.ErrStatus.Details.Causes = append(err.ErrStatus.Details.Causes, metav1.StatusCause{
441				Type:    policyv1.DisruptionBudgetCause,
442				Message: fmt.Sprintf("The disruption budget %s does not allow evicting pods currently: too many pending evictions not confirmed by PDB controller", pdb.Name),
443			})
444			return err
445		}
446		if pdb.Status.DisruptionsAllowed == 0 {
447			err := errors.NewTooManyRequests("Cannot evict pod as it would violate the pod's disruption budget.", 0)
448			condition := meta.FindStatusCondition(pdb.Status.Conditions, policyv1.DisruptionAllowedCondition)
449			var msg string
450			switch {
451			// check whether sync is failed first because DesiredHealthy and CurrentHealthy are not trustworthy when the sync is failed
452			case condition != nil && condition.Status == metav1.ConditionFalse && len(condition.Message) > 0 && condition.Reason == policyv1.SyncFailedReason:
453				msg = fmt.Sprintf("The disruption budget %s does not allow evicting pods currently because it failed sync: %s", pdb.Name, condition.Message)
454			case pdb.Status.CurrentHealthy <= pdb.Status.DesiredHealthy:
455				msg = fmt.Sprintf("The disruption budget %s needs %d healthy pods and has %d currently", pdb.Name, pdb.Status.DesiredHealthy, pdb.Status.CurrentHealthy)
456			case condition != nil && condition.Status == metav1.ConditionFalse && len(condition.Message) > 0:
457				msg = fmt.Sprintf("The disruption budget %s does not allow evicting pods currently (%s): %s", pdb.Name, condition.Reason, condition.Message)
458			default:
459				msg = fmt.Sprintf("The disruption budget %s does not allow evicting pods currently", pdb.Name)
460			}
461			err.ErrStatus.Details.Causes = append(
462				err.ErrStatus.Details.Causes,
463				metav1.StatusCause{
464					Type:    policyv1.DisruptionBudgetCause,
465					Message: msg,
466				},
467			)
468			return err
469		}
470	
471		pdb.Status.DisruptionsAllowed--
472		if pdb.Status.DisruptionsAllowed == 0 {
473			pdbhelper.UpdateDisruptionAllowedCondition(&pdb)
474		}
475	
476		// If this is a dry-run, we don't need to go any further than that.
477		if dryRun {
478			return nil
479		}
480	
481		if pdb.Status.DisruptedPods == nil {
482			pdb.Status.DisruptedPods = make(map[string]metav1.Time)
483		}
484	
485		// Eviction handler needs to inform the PDB controller that it is about to delete a pod
486		// so it should not consider it as available in calculations when updating PodDisruptions allowed.
487		// If the pod is not deleted within a reasonable time limit PDB controller will assume that it won't
488		// be deleted at all and remove it from DisruptedPod map.
489		pdb.Status.DisruptedPods[podName] = metav1.Time{Time: time.Now()}
490		if _, err := r.podDisruptionBudgetClient.PodDisruptionBudgets(namespace).UpdateStatus(context.TODO(), &pdb, metav1.UpdateOptions{}); err != nil {
491			return err
492		}
493	
494		return nil
495	}
