497	// getPodDisruptionBudgets returns any PDBs that match the pod or err if there's an error.
498	func (r *EvictionREST) getPodDisruptionBudgets(ctx context.Context, pod *api.Pod) ([]policyv1.PodDisruptionBudget, error) {
499		pdbList, err := r.podDisruptionBudgetClient.PodDisruptionBudgets(pod.Namespace).List(context.TODO(), metav1.ListOptions{})
500		if err != nil {
501			return nil, err
502		}
503	
504		var pdbs []policyv1.PodDisruptionBudget
505		for _, pdb := range pdbList.Items {
506			if pdb.Namespace != pod.Namespace {
507				continue
508			}
509			selector, err := metav1.LabelSelectorAsSelector(pdb.Spec.Selector)
510			if err != nil {
511				// This object has an invalid selector, it does not match the pod
512				continue
513			}
514			if !selector.Matches(labels.Set(pod.Labels)) {
515				continue
516			}
517	
518			pdbs = append(pdbs, pdb)
519		}
520	
521		return pdbs, nil
522	}
